import type { ComponentProps } from 'react'
import { cn, clamp } from '~/lib/utils'

type GalleryPaginationProps = {
  count: number
  index: number
} & ComponentProps<'div'>

export function GalleryPagination({ count, index, ...divProps }: GalleryPaginationProps) {
  if (!Number.isFinite(count) || count <= 1) {
    return null
  }
  const current = clamp(index, 0, Math.max(0, count - 1))

  return (
    <div
      {...divProps}
      role="group"
      aria-label={`Image ${current + 1} of ${count}`}
      className={cn(
        `
          pointer-events-none inline-flex flex-row items-center gap-1
          rounded-full border border-white/50 bg-black/20 p-1 select-none
        `,
        divProps.className,
      )}
    >
      <span className="sr-only">{`Image ${current + 1} of ${count}`}</span>
      {Array.from({ length: count }).map((_, i) => (
        <span
          key={i}
          aria-hidden="true"
          className={cn(
            `
              block size-1.5 rounded-full transition-[background-color,scale]
              ease-in-out
            `,
            i === current ? 'scale-120 bg-white' : 'scale-100 bg-white/40',
          )}
        />
      ))}
    </div>
  )
}
